import pandas as pd
from pathlib import Path
from config import DATA_PROCESSED_PATH

PROCESSED_DIR = Path(DATA_PROCESSED_PATH).parent


def main():
    frames = []

    # This is the existing processed dataset
    main_df = pd.read_csv(DATA_PROCESSED_PATH)
    frames.append(main_df[["message", "label"]])
    print(f"Main dataset:   {len(main_df)} rows")

    # This is the Latvian synthetic dataset (generated by generate_latvian.py)
    latvian_path = PROCESSED_DIR / "latvian_sms.csv"
    if latvian_path.exists():
        lv_df = pd.read_csv(latvian_path)
        frames.append(lv_df[["message", "label"]])
        print(f"Latvian dataset:    {len(lv_df)} rows")
    else:
        print("Latvian dataset not found. Please run generate_latvian.py first")

    # Merge all datasets, drop duplicates and conflicting labels
    merged = pd.concat(frames, ignore_index=True)
    before = len(merged)

    # Drop exact duplicates on message text
    merged = merged.drop_duplicates(subset="message")

    # Drop conflicting labels (same message labeled both ham and spam)
    conflicts = merged[merged.duplicated(subset="message", keep=False)]
    conflict_msgs = conflicts.groupby("message")["label"].nunique()
    conflict_msgs = conflict_msgs[conflict_msgs > 1].index
    if len(conflict_msgs) > 0:
        print(f"Dropping {len(conflict_msgs)} messages with conflicting labels")
        merged = merged[~merged["message"].isin(conflict_msgs)]

    merged = merged.dropna(subset=["message"])
    merged = merged.reset_index(drop=True)

    after = len(merged)
    print(f"\nMerged: {before} to {after} rows after deduplication")
    print(f"  Spam: {(merged['label'] == 1).sum()}")
    print(f"  Ham:  {(merged['label'] == 0).sum()}")

    # Save the merged dataset back to the processed path
    merged.to_csv(DATA_PROCESSED_PATH, index=False)
    print(f"\nSaved merged dataset to {DATA_PROCESSED_PATH}")


if __name__ == "__main__":
    main()
